const axios = require('axios');
const cheerio = require('cheerio');

class Manhwaland {
    constructor() {
        this.baseUrl = 'https://05c.manhwaland.land';
        this.client = axios.create({
            baseURL: this.baseUrl,
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36',
                'Referer': this.baseUrl,
                'Accept-Language': 'id-ID,id;q=0.9,en-US;q=0.8,en;q=0.7'
            }
        });
    }

    _parseMangaGrid($) {
        const results = [];
        $('.manga-card').each((i, el) => {
            const title = $(el).find('.manga-title').text().trim();
            // Ambil href dari elemen itu sendiri (jika dia <a>) atau cari tag <a> di dalamnya
            const url = $(el).attr('href') || $(el).find('a').first().attr('href');
            const cover = $(el).find('img').attr('src');
            const type = $(el).find('.manga-badge').text().trim();
            const chapter = $(el).find('.group\\/ch span').first().text().trim();

            if (title && url) {
                results.push({ 
                    title, 
                    type: type || null,
                    chapter: chapter || null, 
                    cover, 
                    url: url.startsWith('http') ? url : this.baseUrl + url 
                });
            }
        });
        return results;
    }

    async getHome() {
        try {
            const { data } = await this.client.get('/');
            const $ = cheerio.load(data);

            const popular = [];
            $('#popular .grid a.group.relative').each((i, el) => {
                popular.push({
                    title: $(el).find('h3').text().trim(),
                    cover: $(el).find('img').attr('src'),
                    url: this.baseUrl + $(el).attr('href'),
                    type: $(el).find('.text-white\\/80').text().trim() || 'Manga/Manhwa'
                });
            });

            const latest = [];
            $('#latest .manga-card').each((i, el) => {
                latest.push({
                    title: $(el).find('.manga-title').text().trim(),
                    cover: $(el).find('img').attr('src'),
                    url: this.baseUrl + $(el).find('a').first().attr('href'),
                    type: $(el).find('.manga-badge').text().trim(),
                    latest_chapter: $(el).find('.group\\/ch span').first().text().trim()
                });
            });

            return { success: true, data: { popular, latest } };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getPopular(page = 1) {
        try {
            const { data } = await this.client.get(`/popular?page=${page}`);
            const $ = cheerio.load(data);
            return { success: true, page, data: this._parseMangaGrid($) };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getLatest(page = 1) {
        try {
            const { data } = await this.client.get(`/latest?page=${page}`);
            const $ = cheerio.load(data);
            return { success: true, page, data: this._parseMangaGrid($) };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async search(query, page = 1) {
        try {
            const { data } = await this.client.get(`/search`, {
                params: { q: query, page }
            });
            const $ = cheerio.load(data);
            return { success: true, query, page, data: this._parseMangaGrid($) };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getGenres() {
        try {
            const { data } = await this.client.get('/search');
            const $ = cheerio.load(data);
            const genres = [];

            $('#filter-form [href*="genre="]').each((i, el) => {
                const name = $(el).text().trim();
                const url = $(el).attr('href');
                const match = url.match(/genre=([^&]+)/);
                if (match && name !== 'All') {
                    genres.push({ name, slug: match[1] });
                }
            });

            return { success: true, data: genres };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getGenre(slug, page = 1) {
        try {
            const { data } = await this.client.get(`/genres/${slug}?page=${page}`);
            const $ = cheerio.load(data);
            return { success: true, genre: slug, page, data: this._parseMangaGrid($) };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getDetail(slug) {
        try {
            const { data } = await this.client.get(`/manga/${slug}`);
            const $ = cheerio.load(data);

            const title = $('h1').text().trim();
            const altTitle = $('h2').first().text().trim();
            const cover = $('.w-64 img').attr('src');
            const synopsis = $('h3:contains("Synopsis")').next('div').text().trim();

            const genres = [];
            $('[href^="/genres/"]').each((i, el) => {
                genres.push($(el).text().trim());
            });

            const metadata = {};
            $('.grid-cols-2.md\\:grid-cols-5 > div').each((i, el) => {
                const key = $(el).find('span.text-xs').text().trim().toLowerCase();
                const value = $(el).find('span.font-medium').text().trim();
                if (key) metadata[key] = value;
            });

            const chapters = [];
            $('.max-h-\\[500px\\] a').each((i, el) => {
                chapters.push({
                    title: $(el).find('span').first().text().trim(),
                    date: $(el).find('span').last().text().trim(),
                    url: this.baseUrl + $(el).attr('href')
                });
            });

            return {
                success: true,
                data: {
                    title,
                    altTitle,
                    cover,
                    synopsis,
                    genres,
                    metadata,
                    chapters
                }
            };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }

    async getChapter(url) {
        try {
            const targetUrl = url.startsWith('http') ? url : this.baseUrl + url;
            const { data } = await this.client.get(targetUrl);
            const $ = cheerio.load(data);

            const readerProps = $('astro-island[component-url*="ReaderUI"]').attr('props');
            const images = [];

            if (readerProps) {
                const urlRegex = /"url":\[\d+,"(https:\/\/[^"]+)"\]/g;
                let match;
                while ((match = urlRegex.exec(readerProps)) !== null) {
                    images.push(match[1]);
                }
            }

            const chapterTitle = $('h1.text-lg').text().trim();

            return {
                success: true,
                data: {
                    title: chapterTitle,
                    images: images
                }
            };
        } catch (error) {
            return { success: false, message: error.message };
        }
    }
}

module.exports = Manhwaland;

